import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        a = [int(next(it)) for _ in range(n)]
        best = -10**18  # sufficiently small
        i = 0
        while i < n:
            j = i
            # extend segment while adjacent elements have different parity
            while j + 1 < n and ((a[j] % 2) != (a[j + 1] % 2)):
                j += 1
            # Kadane's algorithm on the segment a[i..j]
            max_ending = a[i]
            max_sofar = a[i]
            for k in range(i + 1, j + 1):
                x = a[k]
                if max_ending + x < x:
                    max_ending = x
                else:
                    max_ending = max_ending + x
                if max_ending > max_sofar:
                    max_sofar = max_ending
            if max_sofar > best:
                best = max_sofar
            i = j + 1
        out_lines.append(str(best))
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

