from typing import List

class Solution:
    def colorTheArray(self, n: int, queries: List[List[int]]) -> List[int]:
        # current colors, 0 means uncolored
        nums = [0] * n
        # current number of adjacent equal-colored pairs
        total = 0
        answer = []

        for idx, color in queries:
            old = nums[idx]
            # Only if the color actually changes we need to update the count
            if old != color:
                # left neighbor
                if idx - 1 >= 0:
                    left = nums[idx - 1]
                    if left != 0 and old != 0 and left == old:
                        total -= 1          # pair (idx-1, idx) was counted, now it may change
                    if left != 0 and color != 0 and left == color:
                        total += 1          # pair (idx-1, idx) becomes counted after the change
                # right neighbor
                if idx + 1 < n:
                    right = nums[idx + 1]
                    if right != 0 and old != 0 and right == old:
                        total -= 1
                    if right != 0 and color != 0 and right == color:
                        total += 1
                nums[idx] = color   # apply the new color
            # if old == color, nothing changes, total stays the same
            answer.append(total)

        return answer
