class Solution:
    def punishmentNumber(self, n: int) -> int:
        def can_partition(s: str, target: int) -> bool:
            """Return True if the string s can be split into contiguous substrings
            whose integer values sum to target."""
            def dfs(idx: int, cur_sum: int) -> bool:
                if idx == len(s):
                    return cur_sum == target
                # prune if we already exceeded the needed sum
                if cur_sum > target:
                    return False
                num = 0
                # try every possible next cut starting at idx
                for j in range(idx, len(s)):
                    num = num * 10 + (ord(s[j]) - 48)  # build number incrementally
                    # if the number we would add is too large, further extensions will only increase it
                    if num > target - cur_sum:
                        break
                    if dfs(j + 1, cur_sum + num):
                        return True
                return False
            return dfs(0, 0)

        total = 0
        for i in range(1, n + 1):
            sq = i * i
            if can_partition(str(sq), i):
                total += sq
        return total
