class Solution:
    def makeSmallestPalindrome(self, s: str) -> str:
        n = len(s)
        chars = list(s)
        for i in range(n // 2):
            j = n - 1 - i
            if chars[i] != chars[j]:
                # To keep the palindrome lexicographically smallest,
                # set both positions to the smaller character.
                smaller = min(chars[i], chars[j])
                chars[i] = chars[j] = smaller
        return ''.join(chars)
