from typing import List

class DSU:
    def __init__(self, n: int):
        self.parent = list(range(n))
        self.size = [1] * n

    def find(self, x: int) -> int:
        # Path compression
        while self.parent[x] != x:
            self.parent[x] = self.parent[self.parent[x]]
            x = self.parent[x]
        return x

    def union(self, x: int, y: int) -> None:
        rx, ry = self.find(x), self.find(y)
        if rx == ry:
            return
        # Union by size
        if self.size[rx] < self.size[ry]:
            rx, ry = ry, rx
        self.parent[ry] = rx
        self.size[rx] += self.size[ry]


class Solution:
    def canTraverseAllPairs(self, nums: List[int]) -> bool:
        n = len(nums)
        if n <= 1:
            return True

        # If any element is 1, it cannot connect to anything else.
        if any(v == 1 for v in nums):
            return False

        max_val = max(nums)
        # Compute smallest prime factor (SPF) for each number up to max_val
        spf = list(range(max_val + 1))
        spf[0] = 0
        if max_val >= 1:
            spf[1] = 1
        for i in range(2, int(max_val ** 0.5) + 1):
            if spf[i] == i:  # i is prime
                step = i
                start = i * i
                for j in range(start, max_val + 1, step):
                    if spf[j] == j:
                        spf[j] = i

        dsu = DSU(n)
        prime_to_index = {}  # maps a prime factor to the first index that had it

        for idx, val in enumerate(nums):
            # Factorize val into distinct prime factors using SPF
            x = val
            last_p = 0
            while x > 1:
                p = spf[x]
                # Skip duplicate factors
                if p != last_p:
                    if p not in prime_to_index:
                        prime_to_index[p] = idx
                    else:
                        dsu.union(idx, prime_to_index[p])
                    last_p = p
                # Divide out all occurrences of p
                while x % p == 0:
                    x //= p

        # Check if all indices belong to the same component
        root = dsu.find(0)
        for i in range(1, n):
            if dsu.find(i) != root:
                return False
        return True
