from collections import Counter

class Solution:
    def relocateMarbles(self, nums: List[int], moveFrom: List[int], moveTo: List[int]) -> List[int]:
        # Count marbles at each position
        cnt = Counter(nums)

        # Process each move
        for src, dst in zip(moveFrom, moveTo):
            if src == dst:
                continue  # no effect when source equals destination
            move_cnt = cnt[src]          # marbles to move
            cnt[dst] = cnt.get(dst, 0) + move_cnt  # add to destination
            del cnt[src]                 # source becomes empty

        # Return sorted occupied positions
        return sorted(cnt.keys())

