class Solution:
    def sumOfSquares(self, nums: List[int]) -> int:
        """
        Returns the sum of squares of elements at 1-indexed positions i
        where i divides the length of the array.
        """
        n = len(nums)
        total = 0
        for i in range(1, n + 1):
            if n % i == 0:
                total += nums[i - 1] * nums[i - 1]
        return total

