from typing import List

class Solution:
    def specialPerm(self, nums: List[int]) -> int:
        MOD = 10**9 + 7
        n = len(nums)
        full_mask = (1 << n) - 1

        # Precompute adjacency: can two numbers be placed next to each other?
        adj = [[False] * n for _ in range(n)]
        for i in range(n):
            for j in range(n):
                if i == j:
                    continue
                a, b = nums[i], nums[j]
                if a % b == 0 or b % a == 0:
                    adj[i][j] = True

        # dp[mask][last] = number of ways to form a permutation of 'mask' ending with index 'last'
        dp = [[0] * n for _ in range(1 << n)]
        for i in range(n):
            dp[1 << i][i] = 1  # single-element permutations

        for mask in range(1 << n):
            # iterate over possible last elements in current mask
            for last in range(n):
                if not (mask & (1 << last)):
                    continue
                cur = dp[mask][last]
                if cur == 0:
                    continue
                # try to append a new element 'nxt'
                for nxt in range(n):
                    if mask & (1 << nxt):
                        continue
                    if adj[last][nxt]:
                        nxt_mask = mask | (1 << nxt)
                        dp[nxt_mask][nxt] = (dp[nxt_mask][nxt] + cur) % MOD

        # Sum over all permutations that use all elements
        ans = sum(dp[full_mask][last] for last in range(n)) % MOD
        return ans
```
This solution uses DP over subsets (bitmask) to count all valid permutations, checking the divisibility condition via a precomputed adjacency matrix. The time complexity is O(n²·2ⁿ) and fits easily within the constraints (n ≤ 14). The result is returned modulo 10⁹+7.

