from typing import List

class Solution:
    def maximumJumps(self, nums: List[int], target: int) -> int:
        n = len(nums)
        NEG = -10**9          # sentinel for unreachable states
        dp = [NEG] * n
        dp[0] = 0             # starting position requires 0 jumps

        for i in range(n):
            if dp[i] == NEG:  # cannot reach i, skip
                continue
            for j in range(i + 1, n):
                if abs(nums[j] - nums[i]) <= target:
                    # we can jump from i to j
                    if dp[i] + 1 > dp[j]:
                        dp[j] = dp[i] + 1

        return dp[n - 1] if dp[n - 1] != NEG else -1
