class Solution:
    def distanceTraveled(self, mainTank: int, additionalTank: int) -> int:
        # Number of times we can transfer 1 liter from additional to main tank.
        if mainTank < 5:
            transfers = 0
        else:
            # Maximum possible transfers based solely on mainTank:
            # After each transfer, mainTank effectively loses 4 liters.
            # We can keep transferring while mainTank >= 5 before the transfer.
            max_transfers = (mainTank - 5) // 4 + 1
            transfers = min(additionalTank, max_transfers)
        # Each transfer gives an extra liter of fuel, i.e., +10 km.
