class Solution:
    def numberOfGoodSubarraySplits(self, nums: List[int]) -> int:
        MOD = 10**9 + 7

        prev_one = -1          # index of the previous 1 we saw
        ans = 1
        found_one = False

        for i, v in enumerate(nums):
            if v == 1:
                if not found_one:
                    # first 1 encountered
                    found_one = True
                    prev_one = i
                else:
                    # gap of zeros between this 1 and the previous one
                    gap = i - prev_one - 1
                    ans = ans * (gap + 1) % MOD
                    prev_one = i

        # if there was no 1 at all, no valid split exists
        return ans if found_one else 0

