class Solution:
    def alternatingSubarray(self, nums: List[int]) -> int:
        n = len(nums)
        max_len = 0

        for i in range(n - 1):
            # The first difference must be +1 to start an alternating subarray
            if nums[i + 1] - nums[i] != 1:
                continue

            length = 2          # we already have nums[i], nums[i+1]
            expected = -1       # next difference should be -1, then +1, ...
            j = i + 2

            while j < n:
                if nums[j] - nums[j - 1] == expected:
                    length += 1
                    expected = -expected   # flip the expected difference
                    j += 1
                else:
                    break

            if length > max_len:
                max_len = length

        return max_len if max_len > 1 else -1
