import math

class Solution:
    def findPrimePairs(self, n: int) -> List[List[int]]:
        # If n is less than 4, the smallest possible prime pair (2,2) cannot be formed.
        if n < 4:
            return []

        # Sieve of Eratosthenes to compute primality up to n.
        is_prime = [True] * (n + 1)
        is_prime[0] = is_prime[1] = False
        limit = int(math.isqrt(n))
        for i in range(2, limit + 1):
            if is_prime[i]:
                for j in range(i * i, n + 1, i):
                    is_prime[j] = False

        # Collect pairs (x, y) with x <= y, x + y = n, and both prime.
        result: List[List[int]] = []
        for x in range(2, n // 2 + 1):
            y = n - x
            if is_prime[x] and is_prime[y]:
                result.append([x, y])

        return result
