class Solution:
    MOD = 10**9 + 7

    def numberOfWays(self, n: int, x: int) -> int:
        # Generate all i^x such that i^x <= n
        powers = []
        i = 1
        while True:
            val = i ** x
            if val > n:
                break
            powers.append(val)
            i += 1

        # DP for subset sum counting (each power can be used at most once)
        dp = [0] * (n + 1)
        dp[0] = 1  # empty set gives sum 0

        for p in powers:
            # iterate backwards to avoid reusing the same element
            for s in range(n, p - 1, -1):
                dp[s] = (dp[s] + dp[s - p]) % self.MOD

        return dp[n]

