    def minimumIndex(self, nums: List[int]) -> int:
        n = len(nums)
        if n < 2:
            return -1

        # Find the dominant element using Boyer-Moore majority vote
        candidate = None
        count = 0
        for x in nums:
            if count == 0:
                candidate = x
                count += 1 if x == candidate else -1
            else:
                count += 1 if x == candidate else -1

        # Verify (optional, given problem guarantee)
        total = sum(1 for x in nums if x == candidate)
        if total * 2 <= n:
            # No dominant element (should not happen per problem statement)
            return -1

        dom = candidate
        left_count = 0
        # Iterate possible split points
        for i in range(n - 1):
            if nums[i] == dom:
                left_count += 1
            left_len = i + 1
            right_len = n - left_len
            right_count = total - left_count
            if left_count * 2 > left_len and right_count * 2 > right_len:
                return i
        return -1

