class Solution:
    def maxSum(self, nums: List[int]) -> int:
        # Helper to compute the maximum digit of a number
        def max_digit(x: int) -> int:
            md = 0
            while x:
                md = max(md, x % 10)
                x //= 10
            return md

        # Group numbers by their maximum digit
        groups = {}
        for num in nums:
            d = max_digit(num)
            groups.setdefault(d, []).append(num)

        best = -1
        # For each group with at least two numbers, take the two largest
        for lst in groups.values():
            if len(lst) < 2:
                continue
            lst.sort(reverse=True)          # descending order
            candidate_sum = lst[0] + lst[1]
            if candidate_sum > best:
                best = candidate_sum

        return best
