        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]

        # dp[l][r] == True if subarray nums[l..r] can be split into singletons
        dp = [[False] * n for _ in range(n)]
        for i in range(n):
            dp[i][i] = True  # length 1 is already a singleton

        # Consider subarrays of increasing length
        for length in range(2, n + 1):
            for l in range(0, n - length + 1):
                r = l + length - 1
                # Try every possible split point k between l and r-1
                for k in range(l, r):
                    left_len = k - l + 1
                    right_len = r - k
                    sum_left = prefix[k + 1] - prefix[l]
                    sum_right = prefix[r + 1] - prefix[k + 1]

                    left_ok = (left_len == 1) or (sum_left >= m)
                    right_ok = (right_len == 1) or (sum_right >= m)

                    if left_ok and right_ok and dp[l][k] and dp[k + 1][r]:
                        dp[l][r] = True
                        break  # no need to check other splits for this interval

        return dp[0][n - 1]

