class Solution:
    def minimumSeconds(self, nums: List[int]) -> int:
        n = len(nums)
        # Store positions for each distinct value
        pos = defaultdict(list)
        for i, v in enumerate(nums):
            pos[v].append(i)

        ans = n  # maximum possible seconds is n (actually floor(n/2) but n is safe upper bound)

        for indices in pos.values():
            # If the value already fills the whole array, no seconds needed
            if len(indices) == n:
                return 0

            max_gap = 0
            m = len(indices)
            # Compute gaps between consecutive occurrences (circular)
            for i in range(m):
                if i + 1 < m:
                    gap = indices[i + 1] - indices[i]
                else:
                    gap = indices[0] + n - indices[-1]  # wrap‑around gap
                if gap > max_gap:
                    max_gap = gap

            # Seconds needed for this value is floor(max_gap / 2)
            seconds = max_gap // 2
            if seconds < ans:
                ans = seconds

        return ans
