    def minAbsoluteDifference(self, nums: List[int], x: int) -> int:
        """
        Returns the minimum absolute difference between two elements whose indices
        are at least x apart.
        """
        n = len(nums)
        if n == 0:
            return 0  # not expected per constraints

        # Treap node definition
        class Node:
            __slots__ = ('key', 'prio', 'left', 'right')
            def __init__(self, key: int):
                self.key = key
                self.prio = random.randrange(1 << 30)
                self.left: Optional['Node'] = None
                self.right: Optional['Node'] = None

        # Helper rotations
        def rotate_right(p: Node) -> Node:
            q = p.left
            p.left = q.right
            q.right = p
            return q

        def rotate_left(p: Node) -> Node:
            q = p.right
            p.right = q.left
            q.left = p
            return q

        # Insert key into treap (no duplicates stored)
        def treap_insert(root: Optional[Node], key: int) -> Optional[Node]:
            if root is None:
                return Node(key)
            if key < root.key:
                root.left = treap_insert(root.left, key)
                if root.left.prio < root.prio:
                    root = rotate_right(root)
            elif key > root.key:
                root.right = treap_insert(root.right, key)
                if root.right.prio < root.prio:
                    root = rotate_left(root)
            # if key == root.key: do nothing (duplicate)
            return root

        # Check if key exists in treap
        def treap_contains(root: Optional[Node], key: int) -> bool:
            while root:
                if root.key == key:
                    return True
                if key < root.key:
                    root = root.left
                else:
                    root = root.right
            return False

        # Predecessor: largest key < given key
        def treap_predecessor(root: Optional[Node], key: int) -> Optional[int]:
            pred = None
            while root:
                if root.key < key:
                    pred = root.key
                    root = root.right
                else:
                    root = root.left
            return pred

        # Successor: smallest key > given key
        def treap_successor(root: Optional[Node], key: int) -> Optional[int]:
            succ = None
            while root:
                if root.key > key:
                    succ = root.key
                    root = root.left
                else:
                    root = root.right
            return succ

        root: Optional[Node] = None
        left = 0
        INF = 10**18
        ans = INF

        for i in range(n):
            # Make indices <= i - x available in the treap
            while left <= i - x:
                root = treap_insert(root, nums[left])
                left += 1

            if root is None:
                continue  # no valid left elements yet

            # If we already have the same value, answer is zero
            if treap_contains(root, nums[i]):
                return 0

            pred = treap_predecessor(root, nums[i])
            succ = treap_successor(root, nums[i])

            if pred is not None:
                diff = abs(nums[i] - pred)
                if diff < ans:
