    def maximumSum(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 0:
            return 0

        # Precompute primes up to sqrt(n) (since we only need to factor indices 1..n)
        limit = int(n ** 0.5) + 1
        is_prime = [True] * (limit + 1)
        is_prime[0] = is_prime[1] = False
        for i in range(2, int(limit ** 0.5) + 1):
            if is_prime[i]:
                step = i
                start = i * i
                for j in range(start, limit + 1, step):
                    is_prime[j] = False
        primes = [i for i, val in enumerate(is_prime) if val]

        def square_free_part(x: int) -> int:
            """Return the product of primes with odd exponent in x."""
            res = 1
            for p in primes:
                if p * p > x:
                    break
                cnt = 0
                while x % p == 0:
                    x //= p
                    cnt ^= 1          # toggle parity
                if cnt:
                    res *= p
            if x > 1:                 # remaining prime factor (exponent 1)
                res *= x
            return res

        sum_by_sf = defaultdict(int)
        for idx in range(1, n + 1):
            sf = square_free_part(idx)
            sum_by_sf[sf] += nums[idx - 1]

        return max(sum_by_sf.values())
