from typing import List

class Solution:
    def maxSubarrays(self, nums: List[int]) -> int:
        # If the AND of the whole array is non-zero, we cannot split
        # into more than one subarray while keeping the sum minimal.
        overall_and = nums[0]
        for v in nums[1:]:
            overall_and &= v
        if overall_and != 0:
            return 1

        # Otherwise, we need the maximum number of subarrays whose AND is zero.
        ans = 0
        cur = -1          # -1 has all bits set in two's complement representation
        for v in nums:
            cur &= v
            if cur == 0:
                ans += 1
                cur = -1   # start a new segment
        return ans

