class Solution:
    def lengthOfLongestSubsequence(self, nums: List[int], target: int) -> int:
        # dp[s] = maximum length of a subsequence that sums to s; -1 means unreachable
        dp = [-1] * (target + 1)
        dp[0] = 0  # empty subsequence gives sum 0 with length 0

        for num in nums:
            # traverse backwards to ensure each number is used at most once
            for s in range(target, num - 1, -1):
                if dp[s - num] != -1:
                    dp[s] = max(dp[s], dp[s - num] + 1)

        return dp[target] if dp[target] != -1 else -1
