class Solution:
    def shortestBeautifulSubstring(self, s: str, k: int) -> str:
        """
        Returns the lexicographically smallest substring of s that:
        - contains exactly k occurrences of '1'
        - has the minimum possible length among all such substrings.
        If no such substring exists, returns an empty string.
        """
        n = len(s)
        best_len = float('inf')
        best_str = ""

        for i in range(n):
            ones = 0
            for j in range(i, n):
                if s[j] == '1':
                    ones += 1
                # If we already have more than k ones, extending further
                # can only increase (or keep) the count, so break.
                if ones > k:
                    break
                if ones == k:
                    cur_len = j - i + 1
                    cur_str = s[i:j+1]
                    if cur_len < best_len:
                        best_len = cur_len
                        best_str = cur_str
                    elif cur_len == best_len and cur_str < best_str:
                        best_str = cur_str

        return best_str if best_len != float('inf') else ""

