class Solution:
    def minSum(self, nums1: List[int], nums2: List[int]) -> int:
        # Compute sum of non-zero elements and count of zeros for each array
        sum1, z1 = 0, 0
        for x in nums1:
            if x == 0:
                z1 += 1
            else:
                sum1 += x

        sum2, z2 = 0, 0
        for x in nums2:
            if x == 0:
                z2 += 1
            else:
                sum2 += x

        # Minimum achievable sum for each array (all zeros replaced by 1)
        base1 = sum1 + z1
        base2 = sum2 + z2

        # Case analysis based on presence of zeros
        if z1 == 0 and z2 == 0:
            # Both sums are fixed
            return sum1 if sum1 == sum2 else -1
        if z1 == 0:
            # nums1 sum is fixed, must be >= base2 to match nums2
            return sum1 if sum1 >= base2 else -1
        if z2 == 0:
            # nums2 sum is fixed, must be >= base1 to match nums1
            return sum2 if sum2 >= base1 else -1
        # Both arrays have at least one zero: we can raise the lower base to the higher one
        return max(base1, base2)
