class Solution:
    def minChanges(self, s: str) -> int:
        """
        Returns the minimum number of character changes required to make the binary string
        s beautiful. A string is beautiful if it can be partitioned into substrings of even
        length, each consisting of identical characters.

        Observation: For such a partition to exist, every pair (s[2k], s[2k+1]) must contain
        the same character. Hence we only need to count how many of these pairs are mismatched;
        each mismatch can be fixed by changing one character.
        """
        changes = 0
        # Iterate over the string two characters at a time
        for i in range(0, len(s), 2):
            if s[i] != s[i + 1]:
                changes += 1
        return changes

