class Solution:
    def minimumSum(self, nums: List[int]) -> int:
        n = len(nums)
        INF = float('inf')
        best = INF

        # Treat each index j as the peak of the mountain
        for j in range(1, n - 1):
            # Minimum value on the left that is smaller than nums[j]
            left_min = INF
            for i in range(j):
                if nums[i] < nums[j] and nums[i] < left_min:
                    left_min = nums[i]

            # Minimum value on the right that is smaller than nums[j]
            right_min = INF
            for k in range(j + 1, n):
                if nums[k] < nums[j] and nums[k] < right_min:
                    right_min = nums[k]

            # If both sides have a valid smaller element, update answer
            if left_min != INF and right_min != INF:
                best = min(best, left_min + nums[j] + right_min)

        return -1 if best == INF else best
