class Solution:
    def findKOr(self, nums: List[int], k: int) -> int:
        result = 0
        # Since nums[i] < 2^31, we need to consider bits 0 through 30.
        for bit in range(31):
            mask = 1 << bit
            # Count how many numbers have this bit set.
            cnt = sum(1 for num in nums if num & mask)
            # If at least k numbers have the bit set, include it in the answer.
            if cnt >= k:
                result |= mask
        return result

