class Solution:
    def findMissingAndRepeatedValues(self, grid: List[List[int]]) -> List[int]:
        n = len(grid)
        total = n * n
        # Boolean array to track which numbers have been seen.
        seen = [False] * (total + 1)  # indices 0..total, we ignore index 0
        duplicate = -1

        # First pass: find the duplicate.
        for row in grid:
            for val in row:
                if seen[val]:
                    duplicate = val          # this value appears twice
                else:
                    seen[val] = True

        # Second pass: find the missing number.
        missing = -1
        for i in range(1, total + 1):
            if not seen[i]:
                missing = i
                break

        return [duplicate, missing]
