class Solution:
    def getGoodIndices(self, variables: List[List[int]], target: int) -> List[int]:
        good_indices = []
        for idx, (a, b, c, m) in enumerate(variables):
            # Step 1: compute a^b modulo 10
            base_mod = pow(a, b, 10)
            # Step 2: compute (base_mod)^c modulo m
            result = pow(base_mod, c, m)
            if result == target:
                good_indices.append(idx)
        return good_indices

