class Solution:
    def minimumCost(self, source: str, target: str, original: List[str], changed: List[str], cost: List[int]) -> int:
        INF = 10**15                     # larger than any possible total cost
        # distance matrix for 26 lowercase letters
        dist = [[INF] * 26 for _ in range(26)]
        for i in range(26):
            dist[i][i] = 0               # zero cost to stay the same

        # keep the cheapest direct edge for each pair
        for u_ch, v_ch, w in zip(original, changed, cost):
            u = ord(u_ch) - 97
            v = ord(v_ch) - 97
            if w < dist[u][v]:
                dist[u][v] = w

        # Floyd‑Warshall to get all‑pairs shortest paths
        for k in range(26):
            dk = dist[k]
            for i in range(26):
                di = dist[i]
                ik = di[k]
                if ik == INF:
                    continue
                # try to improve i -> j via k
                for j in range(26):
                    new = ik + dk[j]
                    if new < di[j]:
                        di[j] = new

        # accumulate minimal cost for each position
        total = 0
        for s_ch, t_ch in zip(source, target):
            if s_ch == t_ch:
                continue
            u = ord(s_ch) - 97
            v = ord(t_ch) - 97
            d = dist[u][v]
            if d == INF:                 # unreachable transformation
                return -1
            total += d
        return total

