        Returns the length of the longest substring consisting of a single repeated character
        that occurs at least three times in the string s. If no such substring exists, returns -1.
        """
        ans = 0
        n = len(s)
        # Iterate over each possible character
        for ch in map(chr, range(ord('a'), ord('z') + 1)):
            runs = []
            i = 0
            # Extract lengths of consecutive runs of ch
            while i < n:
                if s[i] == ch:
                    j = i
                    while j < n and s[j] == ch:
                        j += 1
                    runs.append(j - i)
                    i = j
                else:
                    i += 1
            if not runs:
                continue
            max_run = max(runs)
            # Try lengths from largest to smallest for this character
            for L in range(max_run, 0, -1):
                total = 0
                for r in runs:
                    if r >= L:
                        total += r - L + 1  # number of substrings of length L in this run
                if total >= 3:
                    ans = max(ans, L)
                    break  # no need to check smaller L for this character
        return ans if ans > 0 else -1

