class Solution:
    def lastNonEmptyString(self, s: str) -> str:
        # Count frequency of each character
        freq = [0] * 26
        for ch in s:
            freq[ord(ch) - 97] += 1

        maxFreq = max(freq)          # Number of rounds needed to empty the string
        seen = [0] * 26              # How many times we've seen each character so far
        result = []

        for ch in s:
            idx = ord(ch) - 97
            if freq[idx] == maxFreq: # Only characters with maximal frequency matter
                seen[idx] += 1
                if seen[idx] == maxFreq:   # This is the last (maxFreq-th) occurrence
                    result.append(ch)

        return ''.join(result)

