    def longestCommonPrefix(self, arr1: List[int], arr2: List[int]) -> int:
        # Store all possible prefixes from arr1 as strings
        prefix_set = set()
        for num in arr1:
            s = str(num)
            # Add each prefix of s
            for i in range(1, len(s) + 1):
                prefix_set.add(s[:i])

        max_len = 0
        # For each number in arr2, check its prefixes from longest to shortest
        for num in arr2:
            s = str(num)
            # Scan from full length down to 1; break early on first match
            for i in range(len(s), 0, -1):
                if s[:i] in prefix_set:
                    if i > max_len:
                        max_len = i
                    break  # no need to check shorter prefixes for this number

        return max_len
```
