class Solution:
    def minimumSubarrayLength(self, nums: List[int], k: int) -> int:
        n = len(nums)
        best = n + 1                     # sentinel larger than any valid length
        for i in range(n):
            cur_or = 0
            for j in range(i, n):
                cur_or |= nums[j]        # OR of subarray nums[i..j]
                if cur_or >= k:
                    best = min(best, j - i + 1)
                    # OR can only stay the same or increase when we extend,
                    # so the first j that satisfies the condition gives the
                    # shortest subarray starting at i.
                    break
        return best if best <= n else -1

