class Solution:
    def minOperationsToMakeMedianK(self, nums: List[int], k: int) -> int:
        # Sort the array to easily access the median position
        nums_sorted = sorted(nums)
        n = len(nums_sorted)
        m = n // 2          # index of the median (upper median for even length)

        ops = 0

        # Elements left of the median must not exceed k
        for i in range(m):
            if nums_sorted[i] > k:
                ops += nums_sorted[i] - k

        # Elements right of the median must be at least k
        for i in range(m + 1, n):
            if nums_sorted[i] < k:
                ops += k - nums_sorted[i]

        # The median itself must become exactly k
        ops += abs(nums_sorted[m] - k)

        return ops

