class Solution:
    def canMakeSquare(self, grid: List[List[str]]) -> bool:
        # There are four possible 2x2 squares in a 3x3 grid:
        # top-left corners: (0,0), (0,1), (1,0), (1,1)
        for i in range(2):
            for j in range(2):
                # Count number of 'B' cells in the current 2x2 square
                b_count = 0
                for di in range(2):
                    for dj in range(2):
                        if grid[i + di][j + dj] == 'B':
                            b_count += 1
                w_count = 4 - b_count
                # If at least three cells share the same color,
                # we can make the square uniform by changing at most one cell.
                if b_count >= 3 or w_count >= 3:
                    return True
        return False
