from typing import List

class Solution:
    def occurrencesOfElement(self, nums: List[int], queries: List[int], x: int) -> List[int]:
        # Collect indices where nums[i] == x
        occ_indices = [i for i, val in enumerate(nums) if val == x]

        # Prepare answer list
        ans = []
        for q in queries:
            # q is 1-indexed; check if enough occurrences exist
            if 1 <= q <= len(occ_indices):
                ans.append(occ_indices[q - 1])
            else:
                ans.append(-1)
        return ans
