class Solution:
    def compressedString(self, word: str) -> str:
        # Result parts will be collected in a list for efficient concatenation
        res = []
        # Initialize current character and its count
        cur_char = word[0] if word else ''
        count = 0

        for ch in word:
            if ch == cur_char and count < 9:
                # Continue the current run, but not exceeding 9
                count += 1
            else:
                # Flush the current run
                res.append(str(count))
                res.append(cur_char)
                # Start a new run
                cur_char = ch
                count = 1

        # Flush the last run
        if count > 0:
            res.append(str(count))
            res.append(cur_char)

        return ''.join(res)

