    it = iter(data)
    n = int(next(it))
    a = [int(next(it)) for _ in range(n)]

    result = [a[0]]
    for i in range(1, n):
        prev = result[-1]
        cur = a[i]
        if abs(prev - cur) == 1:
            result.append(cur)
        else:
            if prev < cur:
                # insert increasing numbers
                for x in range(prev + 1, cur):
                    result.append(x)
            else:
                # insert decreasing numbers
                for x in range(prev - 1, cur, -1):
                    result.append(x)
            result.append(cur)

    print(' '.join(map(str, result)))


