import sys

def solve():
    data = sys.stdin.buffer.read().split()
    it = iter(data)
    try:
        N = int(next(it))
    except StopIteration:
        return
    M = int(next(it))

    parent = list(range(N + 1))
    size = [1] * (N + 1)

    def find(x):
        # iterative path halving
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    def union(a, b):
        ra = find(a)
        rb = find(b)
        if ra == rb:
            return
        if size[ra] < size[rb]:
            ra, rb = rb, ra
        parent[rb] = ra
        size[ra] += size[rb]

    for _ in range(M):
        u = int(next(it))
        v = int(next(it))
        if u != v:
            union(u, v)

    # component id for each vertex
    comp = [0] * (N + 1)
    for i in range(1, N + 1):
        comp[i] = find(i)

    K = int(next(it))
    forbidden = set()
    for _ in range(K):
        x = int(next(it))
        y = int(next(it))
        a = comp[x]
        b = comp[y]
        if a == b:
            # According to the statement this should not happen,
            # but we skip just in case.
            continue
        if a > b:
            a, b = b, a
        forbidden.add((a, b))

    Q = int(next(it))
    out = []
    for _ in range(Q):
        p = int(next(it))
        q = int(next(it))
        a = comp[p]
        b = comp[q]
        if a == b:
            out.append("Yes")
        else:
            if a > b:
                a, b = b, a
            if (a, b) in forbidden:
                out.append("No")
            else:
                out.append("Yes")

    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

