MOD = 998244353

def solve() -> None:
    S = sys.stdin.readline().strip()
    n = len(S)
    # dp[bal] = number of ways for current prefix to have balance = bal
    dp = [0] * (n + 2)  # balance can be at most n
    dp[0] = 1

    for ch in S:
        ndp = [0] * (n + 2)
        if ch == '(':
            for bal in range(n + 1):
                val = dp[bal]
                if val:
                    ndp[bal + 1] = (ndp[bal + 1] + val) % MOD
        elif ch == ')':
            for bal in range(1, n + 1):
                val = dp[bal]
                if val:
                    ndp[bal - 1] = (ndp[bal - 1] + val) % MOD
        else:  # ch == '?'
            for bal in range(n + 1):
                val = dp[bal]
                if not val:
                    continue
                # treat as '('
                ndp[bal + 1] = (ndp[bal + 1] + val) % MOD
                # treat as ')'
                if bal > 0:
                    ndp[bal - 1] = (ndp[bal - 1] + val) % MOD
        dp = ndp

    print(dp[0] % MOD)


