def solve():
    data = sys.stdin.read().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    M = int(next(it))
    lengths = [int(next(it)) for _ in range(N)]

    lo = max(lengths)          # at least the longest word must fit
    hi = sum(lengths) + N      # safe upper bound (sum + spaces <= sum + N-1)

    # Returns the number of lines needed for a given width,
    # or a value > M if it already exceeds M (early stop).
    def lines_needed(width: int) -> int:
        lines = 1
        cur = 0  # current line width (sum of word lengths + spaces)
        for w in lengths:
            if cur == 0:          # first word on the line
                if w > width:
                    return N + 1  # impossible, needs more than M lines
                cur = w
            else:
                # need a space before the word
                if cur + 1 + w > width:
                    lines += 1
                    if lines > M:   # early exit
                        return lines
                    cur = w
                    if w > width:
                        return N + 1
                else:
                    cur += 1 + w
        return lines

    while lo < hi:
        mid = (lo + hi) // 2
        if lines_needed(mid) <= M:
            hi = mid
        else:
            lo = mid + 1

    print(lo)

