import sys

def compute_spf(limit):
    """Smallest prime factor for each number up to limit."""
    spf = list(range(limit + 1))
    if limit >= 0:
        spf[0] = 0
    if limit >= 1:
        spf[1] = 1
    for i in range(2, int(limit ** 0.5) + 1):
        if spf[i] == i:  # i is prime
            for j in range(i * i, limit + 1, i):
                if spf[j] == j:
                    spf[j] = i
    return spf

def squarefree_part(x, spf):
    """Return the squarefree part of x (product of primes with odd exponent)."""
    res = 1
    while x > 1:
        p = spf[x]
        cnt = 0
        while x % p == 0:
            x //= p
            cnt += 1
        if cnt % 2 == 1:
            res *= p
    return res

def main():
    data = sys.stdin.read().split()
    if not data:
        return
    it = iter(data)
    n = int(next(it))
    arr = [int(next(it)) for _ in range(n)]

    zero_cnt = arr.count(0)
    non_zero = [x for x in arr if x != 0]

    freq = {}
    if non_zero:
        max_val = max(non_zero)
        spf = compute_spf(max_val)
        for val in non_zero:
            sf = squarefree_part(val, spf)
            freq[sf] = freq.get(sf, 0) + 1

    # pairs involving at least one zero
    ans = zero_cnt * (n - zero_cnt) + zero_cnt * (zero_cnt - 1) // 2
    # pairs of non‑zero numbers with equal squarefree part
    for f in freq.values():
        ans += f * (f - 1) // 2

    print(ans)

